module temp_sensor_comparator (
    input [3:0] temperature,
    input reset,
    output reg obf_alert
);
    always @(*) begin
        if (reset) 
            obf_alert = 0;
        else 
            obf_alert = (temperature > 4'b1010) ? 1 : 0; // 10 degrees Celsius in binary
    end
endmodule
